class Solution:
    def solve(self, s: str) -> str:
        t = s + "#" + s[::-1]
        n = len(t)
        pi = [0] * n
        for i in range(1, n):
            j = pi[i - 1]
            while j > 0 and t[i] != t[j]:
                j = pi[j - 1]
            if t[i] == t[j]:
                j += 1
            pi[i] = j
        return s[pi[-1]:][::-1] + s

